sql:
SELECT crop_id, SUBSTR(application_result, 1, 1) AS application_result_first_char
FROM application_records
WHERE application_result = 'Successful';

SELECT crop_name
FROM crops
WHERE estimated_yield = (SELECT MAX(estimated_yield) FROM crops);

SELECT name, pounds_active_ingredient
FROM insecticides
ORDER BY pounds_active_ingredient DESC;

SELECT name, application_method, pounds_active_ingredient
FROM insecticides
ORDER BY pounds_active_ingredient DESC;

external_knowledge:
- "pesticides" refers to different types of insecticides;
- "effective on" implies the applications where the insecticides are used on specific crops;
- "typical success rates" indicates the average performance score of the insecticide applications;
- "from the most effective to the least" means the results are sorted by the average performance score in descending order.

sql:
SELECT application_method, AVG(phi_days) AS average_phi_days
FROM insecticides
GROUP BY application_method;

external_knowledge:
- 'cheaper' refers to formulations with a cost per unit less than 10;
- 'more potent' means the concentration of the active ingredient in the formulation is greater than 100;
- The formulations are listed with the most cost-effective ones (lower cost per unit) appearing first.

sql:
SELECT AVG(performance_score) AS average_performance_score
FROM application_records
WHERE control_method = 'Herbicides' AND performance_score > 7;

SELECT name, application_method, formulation_type, pounds_active_ingredient, phi_days, TAN(phi_days) AS tan_phi
FROM insecticides
ORDER BY tan_phi DESC;

SELECT name, manufacturer, pounds_active_ingredient, formulation_type
FROM insecticides
ORDER BY name;

SELECT insecticides.name, applications.weather_conditions
FROM applications
JOIN insecticides ON applications.insecticide_id = insecticides.insecticide_id;
